@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="notepad-container">
    <textarea class="notepad-textarea" @bind="Content" @bind:event="oninput" @bind:after="OnContentChanged"></textarea>

    <div class="notepad-toolbar">
        <span class="notepad-status">
            @if (_lastSaved is not null)
            {
                <span>Last saved at @_lastSaved.Value.ToString("HH:mm:ss")</span>
            }
        </span>
        <button class="btn btn-primary btn-sm" @onclick="SaveNowAsync">Save now</button>
        <button class="btn btn-outline-danger btn-sm" @onclick="ClearAsync">Clear</button>
    </div>
</div>

@code {
    private string Content { get; set; } = string.Empty;
    private DateTime? _lastSaved;
    private string _savedContent = string.Empty;

    private NotepadInterop? _interop;
    private DotNetObjectReference<Notepad>? _dotNetRef;

    private bool HasUnsavedChanges => Content != _savedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            _dotNetRef = DotNetObjectReference.Create(this);

            var restored = await _interop.InitializeAsync(_dotNetRef);
            if (!string.IsNullOrEmpty(restored))
            {
                Content = restored;
                _savedContent = restored;
                StateHasChanged();
            }
        }
    }

    private async Task OnContentChanged()
    {
        if (_interop is not null)
        {
            var module = await JS.InvokeAsync<IJSObjectReference>("import", NotepadInterop.ModulePath);
            await module.InvokeVoidAsync("markDirty");
            await module.DisposeAsync();
        }
    }

    [JSInvokable("OnAutoSave")]
    public async Task OnAutoSave()
    {
        await InvokeAsync(async () =>
        {
            if (HasUnsavedChanges)
            {
                await PerformSaveAsync();
                StateHasChanged();
            }
        });
    }

    private async Task SaveNowAsync()
    {
        await PerformSaveAsync();
    }

    private async Task PerformSaveAsync()
    {
        if (_interop is not null)
        {
            await _interop.SaveAsync(Content);
            _savedContent = Content;
            _lastSaved = DateTime.Now;
        }
    }

    private async Task ClearAsync()
    {
        if (_interop is not null)
        {
            await _interop.ClearAsync();
            Content = string.Empty;
            _savedContent = string.Empty;
            _lastSaved = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_interop is not null)
            await _interop.DisposeAsync();

        _dotNetRef?.Dispose();
    }
}

